import { useEffect, useState } from 'react';
import {
  type LayoutChangeEvent,
  type StyleProp,
  StyleSheet,
  View,
  type ViewStyle,
} from 'react-native';
import Animated, {
  cancelAnimation,
  Easing,
  useAnimatedStyle,
  useSharedValue,
  withRepeat,
  withTiming,
} from 'react-native-reanimated';
import { colors, radii, shadows } from '@/design/tokens';
import { useReducedMotion } from '@/design/useReducedMotion';

export type SkeletonCardShape = 'card' | 'line';

export type SkeletonCardProps = {
  height?: number;
  shape?: SkeletonCardShape;
  style?: StyleProp<ViewStyle>;
  testID?: string;
};

// Loading placeholder per docs/design.md §5.1 ("Loading (3 skeleton cards)") +
// §6 inventory. Shimmer is a translated surface-colored band animated across the
// skeleton's width on a repeating worklet. Reduced-motion short-circuits: the
// placeholder renders with its neutral hairline bg and no moving band.
export function SkeletonCard({
  height = 140,
  shape = 'card',
  style,
  testID,
}: SkeletonCardProps) {
  const reduced = useReducedMotion();
  const progress = useSharedValue(0);
  const [width, setWidth] = useState(0);

  useEffect(() => {
    if (reduced || width === 0) return;
    progress.value = 0;
    progress.value = withRepeat(
      withTiming(1, { duration: 1200, easing: Easing.inOut(Easing.quad) }),
      -1,
      false,
    );
    return () => {
      cancelAnimation(progress);
    };
  }, [reduced, width, progress]);

  const bandWidth = Math.max(80, width * 0.4);

  const animatedStyle = useAnimatedStyle(() => {
    const start = -bandWidth;
    const end = width;
    return {
      transform: [{ translateX: start + (end - start) * progress.value }],
    };
  });

  const handleLayout = (event: LayoutChangeEvent) => {
    const w = event.nativeEvent.layout.width;
    if (w !== width) setWidth(w);
  };

  const outerStyle =
    shape === 'card' ? [styles.card, shadows.hard, { height }] : [styles.line, { height }];

  return (
    <View
      style={[outerStyle, style]}
      onLayout={handleLayout}
      testID={testID}
      accessible
      accessibilityLabel="Loading"
      accessibilityState={{ busy: true }}
    >
      {!reduced && width > 0 ? (
        <Animated.View
          pointerEvents="none"
          style={[styles.shimmer, { width: bandWidth }, animatedStyle]}
        />
      ) : null}
    </View>
  );
}

const styles = StyleSheet.create({
  card: {
    backgroundColor: colors.hairline,
    borderRadius: radii.card,
    borderWidth: 2,
    borderColor: colors.ink,
    overflow: 'hidden',
  },
  line: {
    backgroundColor: colors.hairline,
    borderRadius: radii.image,
    overflow: 'hidden',
  },
  shimmer: {
    position: 'absolute',
    top: 0,
    bottom: 0,
    backgroundColor: colors.surface,
    opacity: 0.6,
  },
});

import { useCallback } from 'react';
import {
  Pressable,
  type StyleProp,
  StyleSheet,
  Text,
  View,
  type ViewStyle,
} from 'react-native';
import Animated, {
  useAnimatedStyle,
  useSharedValue,
  withSpring,
  type WithSpringConfig,
} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
import { useReducedMotion } from '@/design/useReducedMotion';
import { textStyles } from '@/design/typography';
import { StatusPill, type StatusPillStatus } from './StatusPill';

export type CampaignCardCurrency = 'USD' | 'EUR' | 'GBP';

export type CampaignCardProps = {
  title: string;
  listerHandle: string;
  priceCents: number;
  currency?: CampaignCardCurrency;
  preConditionSummary?: string;
  status?: StatusPillStatus;
  onPress?: () => void;
  style?: StyleProp<ViewStyle>;
  testID?: string;
};

const CURRENCY_SYMBOL: Record<CampaignCardCurrency, string> = {
  USD: '$',
  EUR: '€',
  GBP: '£',
};

function formatPrice(priceCents: number, currency: CampaignCardCurrency): string {
  const whole = Math.round(priceCents / 100);
  return `${CURRENCY_SYMBOL[currency]}${whole.toLocaleString('en-US')}`;
}

// Feed cell per docs/design.md §5.1 — hard-shadow card, 2px ink border. Press
// behavior per §1.4 line 103: shadow collapses (3,3) → (0,0) while the card
// translates (3,3) to mimic a physical press. Same animated-shadowOpacity + fixed
// shadowOffset pattern as Button/Chip since iOS shadowOffset is not animatable
// through Reanimated.
export function CampaignCard({
  title,
  listerHandle,
  priceCents,
  currency = 'USD',
  preConditionSummary,
  status,
  onPress,
  style,
  testID,
}: CampaignCardProps) {
  const reduced = useReducedMotion();
  const pressed = useSharedValue(0);
  const interactive = !!onPress;

  const animatedStyle = useAnimatedStyle(() => {
    const v = pressed.value;
    return {
      transform: [{ translateX: v * 3 }, { translateY: v * 3 }],
      shadowOpacity: 1 - v,
    };
  });

  const handlePressIn = useCallback(() => {
    if (!interactive) return;
    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
  }, [interactive, pressed, reduced]);

  const handlePressOut = useCallback(() => {
    if (!interactive) return;
    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
  }, [interactive, pressed, reduced]);

  return (
    <Pressable
      onPress={interactive ? onPress : undefined}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      disabled={!interactive}
      accessibilityRole={interactive ? 'button' : undefined}
      accessibilityLabel={`${title} by ${listerHandle}`}
      testID={testID}
    >
      <Animated.View style={[styles.card, shadows.hard, animatedStyle, style]}>
        <Text style={[textStyles.h2, styles.title]} numberOfLines={2}>
          {title}
        </Text>
        <Text style={[textStyles.mono, styles.handle]} numberOfLines={1}>
          {listerHandle}
        </Text>
        {preConditionSummary ? (
          <Text style={[textStyles.caption, styles.preCondition]} numberOfLines={2}>
            {preConditionSummary}
          </Text>
        ) : null}
        <View style={styles.footerRow}>
          <Text style={[textStyles.h2, styles.price]}>{formatPrice(priceCents, currency)}</Text>
          {status ? <StatusPill status={status} /> : null}
        </View>
      </Animated.View>
    </Pressable>
  );
}

const styles = StyleSheet.create({
  card: {
    backgroundColor: colors.surface,
    borderRadius: radii.card,
    borderWidth: 2,
    borderColor: colors.ink,
    padding: spacing.base,
    gap: spacing.xs,
  },
  title: {
    color: colors.ink,
  },
  handle: {
    color: colors.ink70,
  },
  preCondition: {
    color: colors.ink70,
    marginTop: spacing.xs,
  },
  footerRow: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    marginTop: spacing.sm,
  },
  price: {
    color: colors.ink,
  },
});
